1	import { useMemo } from "react";
2	import { useHealth, useServiceIndex, useMarkets } from "@/lib/query/hooks";
3	import { LoadingPage } from "@/components/ui/Spinner";
4	import { formatCurrency } from "@/lib/utils/format";
5	
6	export default function System() {
7	  const health = useHealth();
8	  const index = useServiceIndex();
9	  const allMarkets = useMarkets();
10	
11	  const statusCounts = allMarkets.data?.markets.reduce(
12	    (acc, m) => {
13	      acc[m.status] = (acc[m.status] || 0) + 1;
14	      return acc;
15	    },
16	    {} as Record<string, number>,
17	  ) ?? {};
18	
19	  const platformStats = useMemo(() => {
20	    const markets = allMarkets.data?.markets ?? [];
21	    return {
22	      totalVolume: markets.reduce((s, m) => s + m.volume, 0),
23	      totalLiquidity: markets.reduce((s, m) => s + m.liquidity, 0),
24	      activeCount: markets.filter((m) => m.status === "active").length,
25	      resolvedCount: markets.filter((m) => m.status === "resolved").length,
26	    };
27	  }, [allMarkets.data]);
28	
29	  const isUp = health.data?.status === "ok";
30	
31	  return (
32	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
33	      <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>System Status</h1>
34	
35	      {/* Health beacon */}
36	      <div style={cardStyle}>
37	        <div style={{ display: "flex", alignItems: "center", gap: "var(--space-sm)" }}>
38	          <div style={{
39	            width: 12,
40	            height: 12,
41	            borderRadius: "50%",
42	            background: health.isLoading ? "var(--color-warning, orange)" : isUp ? "var(--color-success)" : "var(--color-danger)",
43	            boxShadow: isUp ? "0 0 8px var(--color-success)" : undefined,
44	          }} />
45	          <span style={{ fontWeight: 600 }}>
46	            {health.isLoading ? "Checking..." : isUp ? "API Online" : "API Unreachable"}
47	          </span>
48	          {health.data && (
49	            <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)", marginLeft: "auto" }}>
50	              {health.data.service} @ {new Date(health.data.timestamp).toLocaleTimeString()}
51	            </span>
52	          )}
53	        </div>
54	        {health.isError && (
55	          <div style={{ marginTop: "var(--space-sm)", fontSize: "0.8rem", color: "var(--color-danger)" }}>
56	            {health.error instanceof Error ? health.error.message : "Connection failed"}
57	          </div>
58	        )}
59	      </div>
60	
61	      {/* Platform aggregate stats */}
62	      {!allMarkets.isLoading && allMarkets.data && (
63	        <div style={cardStyle}>
64	          <h2 style={sectionTitle}>Platform Stats</h2>
65	          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(140px, 1fr))", gap: "var(--space-sm)" }}>
66	            <CountCard label="Total Volume" value={formatCurrency(platformStats.totalVolume)} raw />
67	            <CountCard label="Total Liquidity" value={formatCurrency(platformStats.totalLiquidity)} raw />
68	            <CountCard label="Active" value={platformStats.activeCount} color="var(--color-success)" />
69	            <CountCard label="Resolved" value={platformStats.resolvedCount} color="var(--color-primary)" />
70	          </div>
71	        </div>
72	      )}
73	
74	      {/* Market counts by status */}
75	      <div style={cardStyle}>
76	        <h2 style={sectionTitle}>Markets</h2>
77	        {allMarkets.isLoading ? (
78	          <LoadingPage />
79	        ) : (
80	          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(120px, 1fr))", gap: "var(--space-sm)" }}>
81	            <CountCard label="Total" value={allMarkets.data?.markets.length ?? 0} />
82	            <CountCard label="Active" value={statusCounts["active"] ?? 0} color="var(--color-success)" />
83	            <CountCard label="Resolved" value={statusCounts["resolved"] ?? 0} color="var(--color-primary)" />
84	            <CountCard label="Closed" value={statusCounts["closed"] ?? 0} />
85	            <CountCard label="Draft" value={statusCounts["draft"] ?? 0} />
86	          </div>
87	        )}
88	      </div>
89	
90	      {/* API info */}
91	      {index.data && (
92	        <div style={cardStyle}>
93	          <h2 style={sectionTitle}>API Surface</h2>
94	          <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)", marginBottom: "var(--space-sm)" }}>
95	            Version: {index.data.meta.apiVersion}
96	          </div>
97	          <div style={{ display: "grid", gap: "var(--space-sm)" }}>
98	            {Object.entries(index.data.routes).map(([group, routes]) => (
99	              <div key={group}>
100	                <div style={{ fontSize: "0.8rem", fontWeight: 600, textTransform: "capitalize", marginBottom: 2 }}>
101	                  {group}
102	                </div>
103	                <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
104	                  {routes.map((r) => (
105	                    <span key={r} style={routeTagStyle}>{r}</span>
106	                  ))}
107	                </div>
108	              </div>
109	            ))}
110	          </div>
111	        </div>
112	      )}
113	    </div>
114	  );
115	}
116	
117	function CountCard({ label, value, color, raw }: { label: string; value: number | string; color?: string; raw?: boolean }) {
118	  return (
119	    <div style={{
120	      padding: "var(--space-sm)",
121	      borderRadius: "var(--radius-sm)",
122	      border: "1px solid var(--color-border)",
123	      background: "var(--color-bg)",
124	      textAlign: "center",
125	    }}>
126	      <div style={{ fontSize: raw ? "1.1rem" : "1.5rem", fontWeight: 700, fontFamily: "var(--font-mono)", color: color ?? "var(--color-text)" }}>
127	        {value}
128	      </div>
129	      <div style={{ fontSize: "0.7rem", color: "var(--color-text-muted)" }}>{label}</div>
130	    </div>
131	  );
132	}
133	
134	const cardStyle: React.CSSProperties = {
135	  padding: "var(--space-md)",
136	  borderRadius: "var(--radius-md)",
137	  border: "1px solid var(--color-border)",
138	  background: "var(--color-bg-surface)",
139	};
140	
141	const sectionTitle: React.CSSProperties = {
142	  fontSize: "1rem",
143	  fontWeight: 600,
144	  marginBottom: "var(--space-sm)",
145	};
146	
147	const routeTagStyle: React.CSSProperties = {
148	  padding: "2px 8px",
149	  borderRadius: 4,
150	  background: "var(--color-bg)",
151	  border: "1px solid var(--color-border)",
152	  fontSize: "0.7rem",
153	  fontFamily: "var(--font-mono)",
154	};
